const output = $input.first().json.output ?? '';
const chatId = $('Normaliser Telegram').first().json.chatId;

const MENU_AUTH = [
  [{ text: '👤 Mon profil' }, { text: '🗂️ Mes catégories' }],
  [{ text: '📦 Mes produits' }, { text: '🔒 Se déconnecter' }]
];
const CAT_MENU = [
  [{ text: '➕ Ajouter catégorie' }, { text: '✏️ Modifier catégorie' }],
  [{ text: '🗑️ Supprimer catégorie' }, { text: '🏠 Accueil' }]
];
const PROD_MENU = [
  [{ text: '➕ Ajouter produit' }, { text: '✏️ Modifier produit' }],
  [{ text: '🗑️ Supprimer produit' }, { text: '🏠 Accueil' }]
];

function ctxKb(text) {
  const l = (text || '').toLowerCase();
  if (l.includes('catégorie')) return CAT_MENU;
  if (l.includes('produit')) return PROD_MENU;
  return MENU_AUTH;
}

let parsed = null;
try { parsed = JSON.parse(output.trim()); } catch(e) {
  try { const m = output.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch(e2) {}
}

if (!parsed) return [{ json: { chatId, text: output.trim() || '...', keyboard: ctxKb(output) } }];

switch (parsed.action) {
  case 'category_added':
    return [{ json: { chatId, text: `✅ Catégorie <b>${parsed.nom}</b> créée !`, keyboard: CAT_MENU } }];
  case 'product_added':
    return [{ json: { chatId, text: `✅ Produit <b>${parsed.nom}</b> ajouté à <b>${parsed.prix} $</b> !`, keyboard: PROD_MENU } }];
  case 'product_updated':
    return [{ json: { chatId, text: `✅ Produit <b>${parsed.nom}</b> mis à jour !`, keyboard: PROD_MENU } }];
  case 'product_deleted':
    return [{ json: { chatId, text: `🗑️ Produit supprimé !`, keyboard: PROD_MENU } }];
  case 'category_updated':
    return [{ json: { chatId, text: `✅ Catégorie <b>${parsed.nom}</b> mise à jour !`, keyboard: CAT_MENU } }];
  case 'category_deleted':
    return [{ json: { chatId, text: `🗑️ Catégorie supprimée !`, keyboard: CAT_MENU } }];
  case 'error':
    return [{ json: { chatId, text: `⚠️ ${parsed.msg}`, keyboard: ctxKb(parsed.msg) } }];
  default:
    return [{ json: { chatId, text: output.trim() || '...', keyboard: MENU_AUTH } }];
}

