// ============================================================
// ROUTER NAVIGATION — CORRECTION CONNEXION + SESSION + SÉCURITÉ
// ============================================================
try {
  const norm    = $('Normaliser Telegram').first().json;
  const chatId  = norm.chatId;
  const sessionId = norm.sessionId;
  const userName  = norm.userName;
  const msgRaw  = norm.userMessage.trim();
  const msg     = msgRaw.toLowerCase();

  // Lecture sécurisée de la session depuis le nœud SQL
  const allRows = $input.all();
  let dbRow = {};
  if (allRows && allRows.length > 0 && allRows[0].json && Object.keys(allRows[0].json).length > 0) {
    dbRow = allRows[0].json;
  }

  const currentStep  = dbRow.step != null ? String(dbRow.step) : null;
  const authenticated = parseInt(String(dbRow.authenticated ?? '0')) || 0;
  let D = {};
  try {
    D = dbRow.data
      ? (typeof dbRow.data === 'string' ? JSON.parse(dbRow.data) : dbRow.data)
      : {};
  } catch(e) { D = {}; }

  // --- Fonctions utilitaires ----------------------------------------
  function esc(v) {
    if (v === null || v === undefined || v === '-' || v === '') return 'NULL';
    return "'" + String(v).replace(/'/g, "''") + "'";
  }
  function mkSaveSQL(step, data, auth) {
    const authVal = (auth !== undefined && auth !== null) ? parseInt(auth) : authenticated;
    const dataStr = JSON.stringify(data || {}).replace(/'/g, "''");
    const stepSQL = (step !== null && step !== undefined) ? esc(step) : 'NULL';
    if (!step && !authVal) {
      return `DELETE FROM vendor_sessions WHERE chat_id = ${esc(chatId)}`;
    }
    return `INSERT INTO vendor_sessions (chat_id, step, data, authenticated)
            VALUES (${esc(chatId)}, ${stepSQL}, '${dataStr}', ${authVal})
            ON DUPLICATE KEY UPDATE step = ${stepSQL}, data = '${dataStr}', authenticated = ${authVal}`;
  }
  function out(route, payload, nextStep, nextData, auth) {
    const authVal = (auth !== undefined && auth !== null) ? parseInt(auth) : authenticated;
    return [{ json: {
      route, chatId, sessionId, userName,
      saveSQL: mkSaveSQL(nextStep, nextData, authVal),
      ...payload
    }}];
  }
  function direct(text, keyboard, ns, nd, auth) {
    return out('direct', { text, keyboard }, ns, nd, auth);
  }
  function toAgent(userMessage, ns, nd, auth) {
    return out('agent', { userMessage }, ns, nd, auth);
  }
  function toCats(catMode, ns, nd, auth) {
    const authVal = (auth !== undefined && auth !== null) ? parseInt(auth) : authenticated;
    return [{ json: {
      route: 'sql_cats', chatId, sessionId, userName, catMode,
      saveSQL: mkSaveSQL(ns, nd, authVal)
    }}];
  }
  function toProds(prodMode, ns, nd, auth) {
    const authVal = (auth !== undefined && auth !== null) ? parseInt(auth) : authenticated;
    return [{ json: {
      route: 'sql_prods', chatId, sessionId, userName, prodMode,
      saveSQL: mkSaveSQL(ns, nd, authVal)
    }}];
  }

  // --- Menus ---------------------------------------------------------
  const MENU_NOT_AUTH = [
    [{ text: "📝 M'inscrire" }, { text: '🔑 Se connecter' }]
  ];
  const MENU_AUTH = [
    [{ text: '👤 Mon profil' }, { text: '🗂️ Mes catégories' }],
    [{ text: '📦 Mes produits' }, { text: '🔒 Se déconnecter' }]
  ];
  const MAIN_MENU = authenticated ? MENU_AUTH : MENU_NOT_AUTH;
  const CAT_MENU = [
    [{ text: '➕ Ajouter catégorie' }, { text: '✏️ Modifier catégorie' }],
    [{ text: '🗑️ Supprimer catégorie' }, { text: '🏠 Accueil' }]
  ];
  const PROD_MENU = [
    [{ text: '➕ Ajouter produit' }, { text: '✏️ Modifier produit' }],
    [{ text: '🗑️ Supprimer produit' }, { text: '🏠 Accueil' }]
  ];

  // ---- LOG POUR DÉBOGUER (apparaît dans la console du navigateur) ----
  console.log('Router step:', currentStep, 'auth:', authenticated, 'msg:', msg);

  // ═══════════════════════════════════════
  // 1. Commandes globales
  // ═══════════════════════════════════════
  if (msg === '❌ annuler' || msg === 'annuler') {
    return direct('❌ Annulé.', MAIN_MENU, null, {}, authenticated);
  }
  if (msg === '/start' || msg === '🏠 accueil' || msg === 'accueil') {
    return direct(`👋 Bonjour ${userName} !\nQue souhaitez-vous faire ?`, MAIN_MENU, null, {}, authenticated);
  }
  if (msg === '/logout' || msg === '🔒 se déconnecter') {
    return direct('👋 Déconnecté.', MENU_NOT_AUTH, null, {}, 0);
  }

  // ═══════════════════════════════════════
  // 2. Connexion (sans demande d'identifiant)
  // ═══════════════════════════════════════
  if (msg === '🔑 se connecter' || msg === '/login') {
    return direct(
      '🔐 Entrez votre mot de passe :',
      [[{ text: '❌ Annuler' }]],
      'login_password',
      { identifiant: chatId },  // l'identifiant est le chat_id actuel
      authenticated
    );
  }

  if (currentStep === 'login_password') {
    const sql = `SELECT COUNT(*) AS cnt FROM vendeurs WHERE telegram_chat_id = ${esc(D.identifiant)} AND password = ${esc(msgRaw)}`;
    return [{ json: { route: 'check_login', chatId, sql, sessionId, userName, saveSQL: '' } }];
  }

  // ═══════════════════════════════════════
  // 3. Inscription
  // ═══════════════════════════════════════
  if (msg === "📝 m'inscrire" || msg === "s'inscrire") {
    return direct('📝 <b>Inscription</b>\n\nNom de votre boutique ?', [[{ text: '❌ Annuler' }]], 'reg_nom', {}, 0);
  }
  if (currentStep === 'reg_nom') {
    if (msgRaw.length < 2) return direct('⚠️ Nom trop court.', [[{ text: '❌ Annuler' }]], 'reg_nom', D, 0);
    return direct(`✅ <b>${msgRaw}</b>\n\nDescription ? <i>(- pour passer)</i>`, [[{ text: '-' }, { text: '❌ Annuler' }]], 'reg_desc', { ...D, nom_boutique: msgRaw }, 0);
  }
  if (currentStep === 'reg_desc') {
    return direct('📞 Téléphone ? <i>(- pour passer)</i>', [[{ text: '-' }, { text: '❌ Annuler' }]], 'reg_tel', { ...D, description: msgRaw === '-' ? null : msgRaw }, 0);
  }
  if (currentStep === 'reg_tel') {
    return direct('📍 Adresse ? <i>(- pour passer)</i>', [[{ text: '-' }, { text: '❌ Annuler' }]], 'reg_adr', { ...D, telephone: msgRaw === '-' ? null : msgRaw }, 0);
  }
  if (currentStep === 'reg_adr') {
    return direct('💳 CID EasyPay ? <i>(- pour passer)</i>', [[{ text: '-' }, { text: '❌ Annuler' }]], 'reg_cid', { ...D, adresse: msgRaw === '-' ? null : msgRaw }, 0);
  }
  if (currentStep === 'reg_cid') {
    return direct('🔑 Token EasyPay ? <i>(- pour passer)</i>', [[{ text: '-' }, { text: '❌ Annuler' }]], 'reg_token', { ...D, cideasypay: msgRaw === '-' ? null : msgRaw }, 0);
  }
  if (currentStep === 'reg_token') {
    return direct('🔐 Mot de passe (obligatoire) :', [[{ text: '❌ Annuler' }]], 'reg_password', { ...D, tokeneasypay: msgRaw === '-' ? null : msgRaw }, 0);
  }
  if (currentStep === 'reg_password') {
    if (msgRaw.length < 4) return direct('⚠️ Mot de passe trop court (min 4).', [[{ text: '❌ Annuler' }]], 'reg_password', D, 0);
    const nd = { ...D, password: msgRaw };
    const recap = `📋 <b>Récapitulatif</b>\n\n🏪 <b>${nd.nom_boutique}</b>\n📝 ${nd.description || '<i>-</i>'}\n📞 ${nd.telephone || '<i>-</i>'}\n📍 ${nd.adresse || '<i>-</i>'}\n💳 CID: ${nd.cideasypay || '<i>-</i>'}\n🔑 Token: ${nd.tokeneasypay ? '✅ fourni' : '<i>-</i>'}\n🔐 Mot de passe défini\n\nConfirmer ?`;
    return direct(recap, [[{ text: '✅ Oui' }, { text: '❌ Non' }]], 'reg_confirm', nd, 0);
  }
  if (currentStep === 'reg_confirm') {
    if (msg === '✅ oui' || msg === 'oui') {
      const sql = `INSERT IGNORE INTO vendeurs (telegram_chat_id, nom_boutique, description, telephone, adresse, cideasypay, tokeneasypay, password, statut) VALUES (${esc(chatId)}, ${esc(D.nom_boutique)}, ${esc(D.description)}, ${esc(D.telephone)}, ${esc(D.adresse)}, ${esc(D.cideasypay)}, ${esc(D.tokeneasypay)}, ${esc(D.password)}, 'en_attente')`;
      return [{ json: { route: 'insert_vendeur', chatId, sessionId, userName, sql, nom_boutique: D.nom_boutique, saveSQL: mkSaveSQL(null, {}, 1) } }];
    }
    return direct('Inscription annulée.', MENU_NOT_AUTH, null, {}, 0);
  }

  // ═══════════════════════════════════════
  // 4. Blocage non authentifié
  // ═══════════════════════════════════════
  if (!authenticated) {
    return direct('🔒 Vous devez être connecté.\nUtilisez 🔑 <b>Se connecter</b> ou 📝 <b>M\'inscrire</b>.', MENU_NOT_AUTH, null, {}, 0);
  }

  // ═══════════════════════════════════════
  // 5. Actions authentifiées
  // ═══════════════════════════════════════
  // --- Catégories ---
  if (currentStep === 'cat_nom') {
    if (msgRaw.length < 2) return direct('⚠️ Nom trop court.', [[{ text: '❌ Annuler' }]], 'cat_nom', D, authenticated);
    const sql = `INSERT INTO categories_vendeur (vendeur_id, nom) SELECT id, ${esc(msgRaw)} FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1`;
    return toAgent(`__INSERT_CAT__\nSQL:${sql}\nNOM:${msgRaw}`, null, {}, authenticated);
  }
  if (currentStep === 'modify_cat_select') {
    return direct(`✏️ Nouveau nom pour <b>${msgRaw}</b> :`, [[{ text: '❌ Annuler' }]], 'modify_cat_new_value', { catName: msgRaw }, authenticated);
  }
  if (currentStep === 'modify_cat_new_value') {
    if (msgRaw.length < 2) return direct('⚠️ Nom trop court.', [[{ text: '❌ Annuler' }]], 'modify_cat_new_value', D, authenticated);
    const sqlSel = `SELECT c.id FROM categories_vendeur c JOIN vendeurs v ON v.id=c.vendeur_id WHERE v.telegram_chat_id=${esc(chatId)} AND c.nom=${esc(D.catName)} LIMIT 1`;
    const sqlUpd = `UPDATE categories_vendeur SET nom=${esc(msgRaw)} WHERE id=(SELECT id FROM (${sqlSel}) tmp)`;
    return toAgent(`__UPDATE_CATEGORY__\nSQL_SELECT:${sqlSel}\nSQL_UPDATE:${sqlUpd}\nNOM:${msgRaw}`, null, {}, authenticated);
  }
  if (currentStep === 'delete_cat_select') {
    return direct(`🗑️ Supprimer <b>${msgRaw}</b> ?`, [[{ text: '✅ Oui, supprimer' }, { text: '❌ Non, annuler' }]], 'delete_cat_confirm', { catName: msgRaw }, authenticated);
  }
  if (currentStep === 'delete_cat_confirm') {
    if (msg === '✅ oui, supprimer' || msg === 'oui') {
      const sqlSel = `SELECT c.id FROM categories_vendeur c JOIN vendeurs v ON v.id=c.vendeur_id WHERE v.telegram_chat_id=${esc(chatId)} AND c.nom=${esc(D.catName)} LIMIT 1`;
      const sqlDel = `DELETE FROM categories_vendeur WHERE id=(SELECT id FROM (${sqlSel}) tmp)`;
      return toAgent(`__DELETE_CATEGORY__\nSQL_SELECT:${sqlSel}\nSQL_DELETE:${sqlDel}`, null, {}, authenticated);
    }
    return direct('Suppression annulée.', CAT_MENU, null, {}, authenticated);
  }

  // --- Produits ---
  if (currentStep === 'prod_nom') {
    if (msgRaw.length < 2) return direct('⚠️ Nom trop court.', [[{ text: '❌ Annuler' }]], 'prod_nom', D, authenticated);
    return direct('📝 Description ? <i>(- pour passer)</i>', [[{ text: '-' }, { text: '❌ Annuler' }]], 'prod_desc', { ...D, prod_nom: msgRaw }, authenticated);
  }
  if (currentStep === 'prod_desc') {
    return toCats('product', 'prod_cat_select', { ...D, prod_desc: msgRaw === '-' ? null : msgRaw }, authenticated);
  }
  if (currentStep === 'prod_cat_select') {
    return direct('💵 Prix ($) ?', [[{ text: '❌ Annuler' }]], 'prod_prix', { ...D, categorie_nom: msgRaw }, authenticated);
  }
  if (currentStep === 'prod_prix') {
    const prix = parseFloat(msgRaw.replace(',', '.'));
    if (isNaN(prix) || prix <= 0) return direct('⚠️ Prix invalide.', [[{ text: '❌ Annuler' }]], 'prod_prix', D, authenticated);
    return direct('📐 Taille ? <i>(- pour passer)</i>', [[{ text: '-' }, { text: '❌ Annuler' }]], 'prod_taille', { ...D, prod_prix: prix }, authenticated);
  }
  if (currentStep === 'prod_taille') {
    const nd = { ...D, prod_taille: msgRaw === '-' ? null : msgRaw };
    const catSub = nd.categorie_nom 
      ? `(SELECT id FROM categories_vendeur WHERE vendeur_id=(SELECT id FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1) AND nom=${esc(nd.categorie_nom)} LIMIT 1)` 
      : `(SELECT id FROM categories_vendeur WHERE vendeur_id=(SELECT id FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1) ORDER BY id LIMIT 1)`;
    const sql = `INSERT INTO produits_vendeur (vendeur_id, categorie_id, nom, description, prix, taille) SELECT id, ${catSub}, ${esc(nd.prod_nom)}, ${esc(nd.prod_desc)}, ${nd.prod_prix}, ${esc(nd.prod_taille)} FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1`;
    return toAgent(`__INSERT_PROD__\nSQL:${sql}\nNOM:${nd.prod_nom}\nPRIX:${nd.prod_prix}`, null, {}, authenticated);
  }
  if (currentStep === 'modify_prod_select') {
    return direct(`✏️ Modifier <b>${msgRaw}</b>\n\nQue modifier ?`, [[{ text: '📛 Nom' }, { text: '📝 Description' }], [{ text: '💵 Prix' }, { text: '📐 Taille' }], [{ text: '❌ Annuler' }]], 'modify_prod_field', { productName: msgRaw }, authenticated);
  }
  if (currentStep === 'modify_prod_field') {
    const fieldMap = { '📛 nom':'nom','📝 description':'description','💵 prix':'prix','📐 taille':'taille','nom':'nom','description':'description','prix':'prix','taille':'taille' };
    const field = fieldMap[msg];
    if (!field) return direct('⚠️ Choisissez un champ.', [[{ text: '📛 Nom' }, { text: '📝 Description' }], [{ text: '💵 Prix' }, { text: '📐 Taille' }], [{ text: '❌ Annuler' }]], 'modify_prod_field', D, authenticated);
    const labels = { nom:'Nom', description:'Description', prix:'Prix ($)', taille:'Taille' };
    return direct(`Nouveau ${labels[field]} pour <b>${D.productName}</b> :`, [[{ text: '❌ Annuler' }]], 'modify_prod_value', { ...D, field }, authenticated);
  }
  if (currentStep === 'modify_prod_value') {
    let value = msgRaw;
    if (D.field === 'prix') {
      const p = parseFloat(value.replace(',', '.'));
      if (isNaN(p) || p <= 0) return direct('⚠️ Prix invalide.', [[{ text: '❌ Annuler' }]], 'modify_prod_value', D, authenticated);
      value = String(p);
    }
    const sqlSel = `SELECT p.id FROM produits_vendeur p JOIN vendeurs v ON v.id=p.vendeur_id WHERE v.telegram_chat_id=${esc(chatId)} AND p.nom=${esc(D.productName)} LIMIT 1`;
    const sqlUpd = `UPDATE produits_vendeur SET ${D.field}=${esc(value)} WHERE id=(SELECT id FROM (${sqlSel}) tmp)`;
    return toAgent(`__UPDATE_PRODUCT__\nSQL_SELECT:${sqlSel}\nSQL_UPDATE:${sqlUpd}\nNOM:${D.productName}`, null, {}, authenticated);
  }
  if (currentStep === 'delete_prod_select') {
    return direct(`🗑️ Supprimer <b>${msgRaw}</b> ?`, [[{ text: '✅ Oui, supprimer' }, { text: '❌ Non, annuler' }]], 'delete_prod_confirm', { productName: msgRaw }, authenticated);
  }
  if (currentStep === 'delete_prod_confirm') {
    if (msg === '✅ oui, supprimer' || msg === 'oui') {
      const sqlSel = `SELECT p.id FROM produits_vendeur p JOIN vendeurs v ON v.id=p.vendeur_id WHERE v.telegram_chat_id=${esc(chatId)} AND p.nom=${esc(D.productName)} LIMIT 1`;
      const sqlDel = `DELETE FROM produits_vendeur WHERE id=(SELECT id FROM (${sqlSel}) tmp)`;
      return toAgent(`__DELETE_PRODUCT__\nSQL_SELECT:${sqlSel}\nSQL_DELETE:${sqlDel}`, null, {}, authenticated);
    }
    return direct('Suppression annulée.', PROD_MENU, null, {}, authenticated);
  }

  if (currentStep) {
    return direct('Session réinitialisée.', MAIN_MENU, null, {}, authenticated);
  }

  if (msg === '👤 mon profil') return out('get_profile_direct', {}, null, {}, authenticated);
  if (msg === '🗂️ mes catégories') return toCats('list', null, {}, authenticated);
  if (msg === '📦 mes produits') return toProds('list', null, {}, authenticated);
  if (msg === '➕ ajouter catégorie') return direct('🗂️ Nom de la catégorie ?', [[{ text: '❌ Annuler' }]], 'cat_nom', {}, authenticated);
  if (msg === '➕ ajouter produit') return direct('📦 Nom du produit ?', [[{ text: '❌ Annuler' }]], 'prod_nom', {}, authenticated);
  if (msg === '✏️ modifier produit') return toProds('modify', 'modify_prod_select', {}, authenticated);
  if (msg === '🗑️ supprimer produit') return toProds('delete', 'delete_prod_select', {}, authenticated);
  if (msg === '✏️ modifier catégorie') return toCats('modify', 'modify_cat_select', {}, authenticated);
  if (msg === '🗑️ supprimer catégorie') return toCats('delete', 'delete_cat_select', {}, authenticated);

  return toAgent(msgRaw, null, {}, authenticated);

} catch (error) {
  console.error('Erreur Router Navigation:', error);
  const chatId = $('Normaliser Telegram')?.first()?.json?.chatId || 'inconnu';
  return [{ json: {
    route: 'direct',
    chatId,
    text: '⚠️ Une erreur interne est survenue. Session réinitialisée.',
    keyboard: [[{ text: '🏠 Accueil' }]],
    saveSQL: `DELETE FROM vendor_sessions WHERE chat_id = '${String(chatId).replace(/'/g, "''")}'`
  }}];
}

const chatId = $('Router Navigation').first().json.chatId;
const nom_boutique = $('Router Navigation').first().json.nom_boutique;
const result = $input.first().json;

let affectedRows = 0;
if (Array.isArray(result)) {
  affectedRows = result[0]?.affectedRows || 0;
} else {
  affectedRows = result.affectedRows || 0;
}

const MENU_AUTH = [
  [{ text: '👤 Mon profil' }, { text: '🗂️ Mes catégories' }],
  [{ text: '📦 Mes produits' }, { text: '🔒 Se déconnecter' }]
];
const MENU_NOT_AUTH = [
  [{ text: '🔑 Se connecter' }, { text: "📝 M'inscrire" }]
];

if (affectedRows > 0) {
  return [{ json: { 
    chatId, 
    text: `🎉 Boutique <b>${nom_boutique}</b> enregistrée !\n⏳ En attente de validation.\nVous êtes maintenant connecté.`, 
    keyboard: MENU_AUTH 
  }}];
} else {
  return [{ json: { 
    chatId, 
    text: "⚠️ Vous êtes déjà inscrit. Utilisez le bouton Se connecter.", 
    keyboard: MENU_NOT_AUTH 
  }}];
}

const chatId = $('Router Navigation').first().json.chatId;
const result = $input.first().json;

let cnt = 0;
try {
  cnt = Array.isArray(result) ? parseInt(result[0]?.cnt ?? 0) : parseInt(result.cnt ?? 0);
} catch(e) { cnt = 0; }

const MENU_AUTH = [
  [{ text: '👤 Mon profil' }, { text: '🗂️ Mes catégories' }],
  [{ text: '📦 Mes produits' }, { text: '🔒 Se déconnecter' }]
];
const MENU_NOT_AUTH = [
  [{ text: '🔑 Se connecter' }, { text: "📝 M'inscrire" }]
];

const chatIdEsc = String(chatId).replace(/'/g, "''");
const saveSQL = cnt > 0
  ? `INSERT INTO vendor_sessions (chat_id, step, data, authenticated) VALUES ('${chatIdEsc}', NULL, '{}', 1) ON DUPLICATE KEY UPDATE step = NULL, data = '{}', authenticated = 1`
  : '';

return [{ json: {
  chatId,
  text: cnt > 0 ? '✅ Connecté avec succès !' : '❌ Identifiant ou mot de passe incorrect.',
  keyboard: cnt > 0 ? MENU_AUTH : MENU_NOT_AUTH,
  saveSQL
}}];

const loginData = $('Handle Login Result').first().json;
return [{ json: {
  chatId: loginData.chatId,
  text: loginData.text,
  keyboard: loginData.keyboard
}}];

const chatId  = $('Normaliser Telegram').first().json.chatId;
const catMode = $('Router Navigation').first().json.catMode || 'list';
const rows    = $input.all().map(i => i.json).filter(r => r && r.nom);

const CAT_MENU = [
  [{ text: '➕ Ajouter catégorie' }, { text: '✏️ Modifier catégorie' }],
  [{ text: '🗑️ Supprimer catégorie' }, { text: '🏠 Accueil' }]
];

if (catMode === 'list') {
  if (!rows.length) return [{ json: { chatId, text: '🗂️ Aucune catégorie.\nUtilisez ➕ Ajouter catégorie.', keyboard: CAT_MENU } }];
  return [{ json: { chatId, text: '🗂️ <b>Vos catégories :</b>\n\n' + rows.map(c => `• <b>${c.nom}</b>`).join('\n'), keyboard: CAT_MENU } }];
}

if (!rows.length) return [{ json: { chatId, text: '⚠️ Aucune catégorie. Créez-en une d\'abord.', keyboard: [[{ text: '➕ Ajouter catégorie' }], [{ text: '🏠 Accueil' }]] } }];

const buttons = [...rows.map(r => [{ text: r.nom }]), [{ text: '❌ Annuler' }]];
const text = catMode === 'modify' ? '✏️ Choisissez la catégorie à modifier :'
           : catMode === 'delete' ? '🗑️ Choisissez la catégorie à supprimer :'
           : '🗂️ Choisissez la <b>catégorie</b> du produit :';
return [{ json: { chatId, text, keyboard: buttons } }];

const chatId   = $('Normaliser Telegram').first().json.chatId;
const prodMode = $('Router Navigation').first().json.prodMode || 'list';
const rows     = $input.all().map(i => i.json).filter(r => r && r.nom);

const PROD_MENU = [
  [{ text: '➕ Ajouter produit' }, { text: '✏️ Modifier produit' }],
  [{ text: '🗑️ Supprimer produit' }, { text: '🏠 Accueil' }]
];

if (prodMode === 'list') {
  if (!rows.length) return [{ json: { chatId, text: '📦 Aucun produit.\nUtilisez ➕ Ajouter produit.', keyboard: PROD_MENU } }];
  const text = '📦 <b>Vos produits :</b>\n\n' + rows.map(p =>
    `• <b>${p.nom}</b> — ${p.prix} $` +
    (p.description ? `\n  <i>${p.description}</i>` : '') +
    (p.taille ? ` | 📐 ${p.taille}` : '')
  ).join('\n\n');
  return [{ json: { chatId, text, keyboard: PROD_MENU } }];
}

if (!rows.length) return [{ json: { chatId, text: '⚠️ Aucun produit. Ajoutez-en un d\'abord.', keyboard: [[{ text: '➕ Ajouter produit' }], [{ text: '🏠 Accueil' }]] } }];

const buttons = [...rows.map(r => [{ text: r.nom }]), [{ text: '❌ Annuler' }]];
const text = prodMode === 'modify' ? '✏️ Choisissez le produit à modifier :' : '🗑️ Choisissez le produit à supprimer :';
return [{ json: { chatId, text, keyboard: buttons } }];

const chatId = $('Normaliser Telegram').first().json.chatId;
const rows   = $input.all().map(i => i.json);
const d      = rows.find(r => r && (r.nom_boutique || r.statut || r.telephone || r.adresse || r.description));

const MAIN_MENU = [
  [{ text: '👤 Mon profil' }, { text: '🗂️ Mes catégories' }],
  [{ text: '📦 Mes produits' }, { text: '🔒 Se déconnecter' }]
];

if (!d) return [{ json: { chatId, text: "❌ Aucun compte. Inscrivez-vous d'abord.", keyboard: [[{ text: "📝 M'inscrire" }], [{ text: '🔑 Se connecter' }]] } }];

function clean(v) { return (v === null || v === undefined || String(v).trim() === '') ? '<i>-</i>' : String(v).trim(); }

const rawStatus = String(d.statut || '').trim().toLowerCase();
const statusMap = {
  'en_attente': '⏳ <b>en_attente</b>',
  'approuvé':   '✅ <b>approuvé</b>',
  'approuve':   '✅ <b>approuvé</b>',
  'rejeté':     '❌ <b>rejeté</b>',
  'rejete':     '❌ <b>rejeté</b>'
};
const statut = statusMap[rawStatus] || '❓ <b>inconnu</b>';

return [{ json: { chatId, text: `👤 <b>Mon Profil</b>\n\n🏪 <b>${clean(d.nom_boutique)}</b>\n📝 ${clean(d.description)}\n📞 ${clean(d.telephone)}\n📍 ${clean(d.adresse)}\nStatut : ${statut}`, keyboard: MAIN_MENU } }];
